package com.securechat.data.repository

import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.firestore.Query
import com.google.firebase.storage.FirebaseStorage
import com.securechat.data.local.dao.MessageDao
import com.securechat.data.mapper.toMessage
import com.securechat.data.mapper.toMessageEntity
import com.securechat.domain.model.*
import com.securechat.domain.repository.ChatRepository
import com.securechat.domain.repository.UserRepository
import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.tasks.await
import java.util.UUID
import javax.inject.Inject
import javax.inject.Singleton

@Singleton
class ChatRepositoryImpl @Inject constructor(
    private val firestore: FirebaseFirestore,
    private val storage: FirebaseStorage,
    private val messageDao: MessageDao,
    private val userRepository: UserRepository
) : ChatRepository {

    override fun getChatRooms(userId: String): Flow<Resource<List<ChatRoom>>> = callbackFlow {
        trySend(Resource.Loading)
        val listener = firestore.collection("rooms")
            .whereArrayContains("members", userId)
            .addSnapshotListener { snapshot, error ->
                if (error != null) {
                    trySend(Resource.Error(error.message ?: "Lỗi tải phòng chat"))
                    return@addSnapshotListener
                }
                val rooms = snapshot?.documents?.mapNotNull { doc ->
                    doc.toObject(ChatRoom::class.java)?.copy(id = doc.id)
                } ?: emptyList()

                val sortedRooms = rooms.sortedByDescending { it.lastMessage?.createdAt }
                trySend(Resource.Success(sortedRooms))
            }
        awaitClose { listener.remove() }
    }

    override suspend fun createRoom(
        name: String,
        memberIds: List<String>,
        isGroup: Boolean
    ): Resource<ChatRoom> {
        return try {
            val names = mutableMapOf<String, String>()
            val photos = mutableMapOf<String, String>()

            for (id in memberIds) {
                val userResult = userRepository.getUser(id)
                if (userResult is Resource.Success) {
                    names[id] = userResult.data.displayName
                    photos[id] = userResult.data.photoUrl ?: ""
                }
            }

            val room = ChatRoom(
                id       = UUID.randomUUID().toString(),
                name     = name,
                members  = memberIds,
                memberNames = names,
                memberPhotos = photos,
                isGroup  = isGroup
            )
            firestore.collection("rooms").document(room.id).set(room).await()
            Resource.Success(room)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Tạo phòng thất bại")
        }
    }

    override suspend fun getChatRoom(roomId: String): Resource<ChatRoom> {
        return try {
            val doc = firestore.collection("rooms").document(roomId).get().await()
            val room = doc.toObject(ChatRoom::class.java)?.copy(id = doc.id)
                ?: return Resource.Error("Không tìm thấy phòng")
            Resource.Success(room)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Lỗi tải phòng")
        }
    }

    override fun getMessages(roomId: String): Flow<Resource<List<Message>>> = flow {
        emit(Resource.Loading)
        val cached = messageDao.getMessagesByRoom(roomId).firstOrNull()
        if (cached != null && cached.isNotEmpty()) emit(Resource.Success(cached.map { it.toMessage() }))

        val remoteFlow: Flow<Resource<List<Message>>> = callbackFlow {
            val listener = firestore.collection("rooms")
                .document(roomId)
                .collection("messages")
                .orderBy("createdAt", Query.Direction.ASCENDING)
                .addSnapshotListener { snapshot, error ->
                    if (error != null) {
                        trySend(Resource.Error(error.message ?: "Lỗi tải tin nhắn"))
                        return@addSnapshotListener
                    }
                    val messages = snapshot?.documents?.mapNotNull { doc ->
                        doc.toObject(Message::class.java)?.copy(id = doc.id)
                    } ?: emptyList()
                    trySend(Resource.Success(messages))
                }
            awaitClose { listener.remove() }
        }

        remoteFlow.collect { result ->
            if (result is Resource.Success) {
                messageDao.insertMessages(result.data.map { it.toMessageEntity() })
            }
            emit(result)
        }
    }

    override suspend fun sendMessage(message: Message): Resource<Unit> {
        return try {
            firestore.collection("rooms")
                .document(message.roomId)
                .collection("messages")
                .document(message.id)
                .set(message)
                .await()

            firestore.collection("rooms")
                .document(message.roomId)
                .update(
                    mapOf(
                        "lastMessage" to message,
                        "lastMessage.createdAt" to message.createdAt
                    )
                ).await()

            messageDao.insertMessage(message.toMessageEntity())
            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Gửi tin nhắn thất bại")
        }
    }

    // THỰC HIỆN HÀM XÓA TIN NHẮN
    override suspend fun deleteMessage(roomId: String, messageId: String): Resource<Unit> {
        return try {
            // Xóa trên Firestore
            firestore.collection("rooms")
                .document(roomId)
                .collection("messages")
                .document(messageId)
                .delete()
                .await()

            // Xóa ở Local Database (Room)
            messageDao.deleteMessage(messageId)

            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Xóa tin nhắn thất bại")
        }
    }

    override suspend fun sendFile(roomId: String, fileUri: String, type: MessageType): Resource<Unit> {
        return Resource.Success(Unit)
    }

    override suspend fun deleteChatRoom(roomId: String): Resource<Unit> {
        return try {
            val roomRef = firestore.collection("rooms").document(roomId)
            val messagesRef = roomRef.collection("messages")
            val batchSize = 200L

            while (true) {
                val snapshot = messagesRef.limit(batchSize).get().await()
                if (snapshot.isEmpty) break

                val batch = firestore.batch()
                snapshot.documents.forEach { doc -> batch.delete(doc.reference) }
                batch.commit().await()

                if (snapshot.size() < batchSize.toInt()) break
            }

            roomRef.delete().await()
            messageDao.deleteRoomMessages(roomId)
            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Xóa phòng chat thất bại")
        }
    }

    override suspend fun markAsRead(roomId: String, userId: String): Resource<Unit> {
        return try {
            firestore.collection("rooms")
                .document(roomId)
                .update("unreadCount.$userId", 0)
                .await()
            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Lỗi đánh dấu đã đọc")
        }
    }
}

package com.securechat.data.repository

import com.google.firebase.firestore.FieldValue
import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.firestore.Query
import com.google.firebase.storage.FirebaseStorage
import com.securechat.data.local.dao.MessageDao
import com.securechat.data.mapper.toMessage
import com.securechat.data.mapper.toMessageEntity
import com.securechat.domain.model.*
import com.securechat.domain.repository.ChatRepository
import com.securechat.domain.repository.UserRepository
import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.tasks.await
import java.util.UUID
import javax.inject.Inject
import javax.inject.Singleton

@Singleton
class ChatRepositoryImpl @Inject constructor(
    private val firestore: FirebaseFirestore,
    private val storage: FirebaseStorage,
    private val messageDao: MessageDao,
    private val userRepository: UserRepository
) : ChatRepository {

    override fun getChatRooms(userId: String): Flow<Resource<List<ChatRoom>>> = callbackFlow {
        trySend(Resource.Loading)
        val listener = firestore.collection("rooms")
            .whereArrayContains("members", userId)
            .addSnapshotListener { snapshot, error ->
                if (error != null) {
                    trySend(Resource.Error(error.message ?: "Lỗi tải phòng chat"))
                    return@addSnapshotListener
                }
                val rooms = snapshot?.documents?.mapNotNull { doc ->
                    doc.toObject(ChatRoom::class.java)?.copy(id = doc.id)
                } ?: emptyList()

                val sortedRooms = rooms.sortedByDescending { it.lastMessage?.createdAt }
                trySend(Resource.Success(sortedRooms))
            }
        awaitClose { listener.remove() }
    }

    override suspend fun createRoom(
        name: String,
        memberIds: List<String>,
        isGroup: Boolean
    ): Resource<ChatRoom> {
        return try {
            val names = mutableMapOf<String, String>()
            val photos = mutableMapOf<String, String>()

            for (id in memberIds) {
                val userResult = userRepository.getUser(id)
                if (userResult is Resource.Success) {
                    names[id] = userResult.data.displayName
                    photos[id] = userResult.data.photoUrl ?: ""
                }
            }

            val room = ChatRoom(
                id       = UUID.randomUUID().toString(),
                name     = name,
                members  = memberIds,
                memberNames = names,
                memberPhotos = photos,
                isGroup  = isGroup
            )
            firestore.collection("rooms").document(room.id).set(room).await()
            Resource.Success(room)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Tạo phòng thất bại")
        }
    }

    override suspend fun getChatRoom(roomId: String): Resource<ChatRoom> {
        return try {
            val doc = firestore.collection("rooms").document(roomId).get().await()
            val room = doc.toObject(ChatRoom::class.java)?.copy(id = doc.id)
                ?: return Resource.Error("Không tìm thấy phòng")
            Resource.Success(room)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Lỗi tải phòng")
        }
    }

    override fun getMessages(roomId: String): Flow<Resource<List<Message>>> = flow {
        emit(Resource.Loading)
        val cached = messageDao.getMessagesByRoom(roomId).firstOrNull()
        if (cached != null && cached.isNotEmpty()) emit(Resource.Success(cached.map { it.toMessage() }))

        val remoteFlow: Flow<Resource<List<Message>>> = callbackFlow {
            val listener = firestore.collection("rooms")
                .document(roomId)
                .collection("messages")
                .orderBy("createdAt", Query.Direction.ASCENDING)
                .addSnapshotListener { snapshot, error ->
                    if (error != null) {
                        trySend(Resource.Error(error.message ?: "Lỗi tải tin nhắn"))
                        return@addSnapshotListener
                    }
                    val messages = snapshot?.documents?.mapNotNull { doc ->
                        doc.toObject(Message::class.java)?.copy(id = doc.id)
                    } ?: emptyList()
                    trySend(Resource.Success(messages))
                }
            awaitClose { listener.remove() }
        }

        remoteFlow.collect { result ->
            if (result is Resource.Success) {
                messageDao.insertMessages(result.data.map { it.toMessageEntity() })
            }
            emit(result)
        }
    }

    override suspend fun sendMessage(message: Message): Resource<Unit> {
        return try {
            val normalizedMessage = message.copy(
                deliveredTo = (message.deliveredTo + message.senderId).distinct(),
                seenBy = (message.seenBy + message.senderId).distinct()
            )

            firestore.collection("rooms")
                .document(normalizedMessage.roomId)
                .collection("messages")
                .document(normalizedMessage.id)
                .set(normalizedMessage)
                .await()

            firestore.collection("rooms")
                .document(normalizedMessage.roomId)
                .update(
                    mapOf(
                        "lastMessage" to normalizedMessage,
                        "lastMessage.createdAt" to normalizedMessage.createdAt
                    )
                ).await()

            messageDao.insertMessage(normalizedMessage.toMessageEntity())
            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Gửi tin nhắn thất bại")
        }
    }

    // THỰC HIỆN HÀM XÓA TIN NHẮN
    override suspend fun deleteMessage(roomId: String, messageId: String): Resource<Unit> {
        return try {
            // Xóa trên Firestore
            firestore.collection("rooms")
                .document(roomId)
                .collection("messages")
                .document(messageId)
                .delete()
                .await()

            // Xóa ở Local Database (Room)
            messageDao.deleteMessage(messageId)

            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Xóa tin nhắn thất bại")
        }
    }

    override suspend fun sendFile(roomId: String, fileUri: String, type: MessageType): Resource<Unit> {
        return Resource.Success(Unit)
    }

    override suspend fun deleteChatRoom(roomId: String): Resource<Unit> {
        return try {
            val roomRef = firestore.collection("rooms").document(roomId)
            val messagesRef = roomRef.collection("messages")
            val batchSize = 200L

            while (true) {
                val snapshot = messagesRef.limit(batchSize).get().await()
                if (snapshot.isEmpty) break

                val batch = firestore.batch()
                snapshot.documents.forEach { doc -> batch.delete(doc.reference) }
                batch.commit().await()

                if (snapshot.size() < batchSize.toInt()) break
            }

            roomRef.delete().await()
            messageDao.deleteRoomMessages(roomId)
            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Xóa phòng chat thất bại")
        }
    }

    override suspend fun markAsRead(roomId: String, userId: String): Resource<Unit> {
        return try {
            firestore.collection("rooms")
                .document(roomId)
                .update("unreadCount.$userId", 0)
                .await()
            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Lỗi đánh dấu đã đọc")
        }
    }

    override suspend fun markMessagesDelivered(roomId: String, userId: String): Resource<Unit> {
        return updateMessageReceipt(roomId, userId, isSeen = false)
    }

    override suspend fun markMessagesSeen(roomId: String, userId: String): Resource<Unit> {
        return updateMessageReceipt(roomId, userId, isSeen = true)
    }

    private suspend fun updateMessageReceipt(roomId: String, userId: String, isSeen: Boolean): Resource<Unit> {
        return try {
            val roomRef = firestore.collection("rooms").document(roomId)
            val snapshot = roomRef.collection("messages")
                .orderBy("createdAt", Query.Direction.DESCENDING)
                .limit(100)
                .get()
                .await()

            val docsToUpdate = snapshot.documents.filter { doc ->
                val senderId = doc.getString("senderId")
                val delivered = (doc.get("deliveredTo") as? List<*>)?.filterIsInstance<String>() ?: emptyList()
                val seen = (doc.get("seenBy") as? List<*>)?.filterIsInstance<String>() ?: emptyList()
                senderId != null && senderId != userId && (userId !in delivered || (isSeen && userId !in seen))
            }

            if (docsToUpdate.isNotEmpty()) {
                val batch = firestore.batch()
                docsToUpdate.forEach { doc ->
                    batch.update(doc.reference, "deliveredTo", FieldValue.arrayUnion(userId))
                    if (isSeen) {
                        batch.update(doc.reference, "seenBy", FieldValue.arrayUnion(userId))
                        batch.update(doc.reference, "isRead", true)
                    }
                }
                batch.commit().await()
            }

            val roomDoc = roomRef.get().await()
            val lastMessageDoc = roomDoc.get("lastMessage") as? Map<*, *>
            val lastSenderId = lastMessageDoc?.get("senderId") as? String
            if (lastSenderId != null && lastSenderId != userId) {
                val roomUpdates = mutableMapOf<String, Any>(
                    "lastMessage.deliveredTo" to FieldValue.arrayUnion(userId)
                )
                if (isSeen) {
                    roomUpdates["lastMessage.seenBy"] = FieldValue.arrayUnion(userId)
                    roomUpdates["lastMessage.isRead"] = true
                }
                roomRef.update(roomUpdates).await()
            }

            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.localizedMessage ?: "Lỗi cập nhật trạng thái tin nhắn")
        }
    }
}

package com.securechat.ui.screens.home

import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import androidx.lifecycle.compose.collectAsStateWithLifecycle
import com.securechat.domain.model.ChatRoom
import java.text.SimpleDateFormat
import java.util.Locale

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun HomeScreen(
    onOpenChat: (roomId: String, roomName: String) -> Unit,
    onSignedOut: () -> Unit,
    viewModel: HomeViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()
    val user = viewModel.currentUser

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("SecureChat") },
                actions = {
                    IconButton(onClick = { viewModel.signOut(onSignedOut) }) {
                        Icon(Icons.Default.Logout, contentDescription = "Đăng xuất")
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = MaterialTheme.colorScheme.primaryContainer
                )
            )
        },
        floatingActionButton = {
            FloatingActionButton(onClick = viewModel::showCreateDialog) {
                Icon(Icons.Default.Add, contentDescription = "Tạo phòng")
            }
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
        ) {
            user?.let {
                Surface(
                    color = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.4f),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Row(
                        modifier = Modifier.padding(horizontal = 16.dp, vertical = 12.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Icon(
                            Icons.Default.AccountCircle,
                            contentDescription = null,
                            modifier = Modifier.size(40.dp),
                            tint = MaterialTheme.colorScheme.primary
                        )
                        Spacer(Modifier.width(12.dp))
                        Column {
                            Text(it.displayName, style = MaterialTheme.typography.titleMedium)
                            Text(it.email,
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant)
                        }
                    }
                }
            }

            HorizontalDivider()

            if (uiState.isLoading && uiState.rooms.isEmpty()) {
                Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                    CircularProgressIndicator()
                }
            } else if (uiState.rooms.isEmpty()) {
                Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(
                            Icons.Default.ChatBubbleOutline,
                            contentDescription = null,
                            modifier = Modifier.size(64.dp),
                            tint = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.5f)
                        )
                        Spacer(Modifier.height(16.dp))
                        Text(
                            "Chưa có cuộc trò chuyện nào",
                            style = MaterialTheme.typography.bodyLarge,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                        Text(
                            "Nhấn + để tạo phòng mới",
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f)
                        )
                    }
                }
            } else {
                LazyColumn {
                    items(
                        items = uiState.rooms,
                        key   = { it.id }
                    ) { room ->
                        RoomItem(
                            room    = room,
                            currentUserId = user?.uid ?: "",
                            onClick = { onOpenChat(room.id, room.name) },
                            onLongClick = { viewModel.showDeleteRoomDialog(room.id) } // Needs to be added to view model
                        )
                        HorizontalDivider(modifier = Modifier.padding(start = 72.dp))
                    }
                }
            }
        }

        if (uiState.showCreateDialog) {
            AlertDialog(
                onDismissRequest = viewModel::dismissCreateDialog,
                title   = { Text("Tạo phòng chat mới") },
                text    = {
                    Column {
                        OutlinedTextField(
                            value = uiState.newRoomName,
                            onValueChange = viewModel::onNewRoomNameChange,
                            label = { Text("Tên phòng") },
                            singleLine = true,
                            modifier = Modifier.fillMaxWidth()
                        )
                        if (uiState.errorMessage != null) {
                            Text(
                                text = uiState.errorMessage!!,
                                color = MaterialTheme.colorScheme.error,
                                style = MaterialTheme.typography.bodySmall,
                                modifier = Modifier.padding(top = 8.dp)
                            )
                        }
                    }
                },
                confirmButton = {
                    TextButton(
                        onClick  = viewModel::createRoom,
                        enabled  = uiState.newRoomName.isNotBlank() && !uiState.isCreating
                    ) { 
                        if (uiState.isCreating) CircularProgressIndicator(Modifier.size(16.dp))
                        else Text("Tạo") 
                    }
                },
                dismissButton = {
                    TextButton(onClick = viewModel::dismissCreateDialog) { Text("Hủy") }
                }
            )
        }
    }
}

@OptIn(androidx.compose.foundation.ExperimentalFoundationApi::class)
@Composable
private fun RoomItem(room: ChatRoom, currentUserId: String, onClick: () -> Unit, onLongClick: () -> Unit) {
    val timeFormat = remember { SimpleDateFormat("HH:mm", Locale.getDefault()) }
    val unread = room.unreadCount[currentUserId] ?: 0
    val isUnread = unread > 0
    val isMine = room.lastMessage?.senderId == currentUserId

    ListItem(
        modifier = Modifier.combinedClickable(
            onClick = onClick,
            onLongClick = onLongClick
        ),
        headlineContent = {
            Text(room.name, style = MaterialTheme.typography.titleMedium, fontWeight = if (isUnread) androidx.compose.ui.text.font.FontWeight.Bold else null)
        },
        supportingContent = {
            val prefix = if (isMine && room.lastMessage != null) "Bạn: " else ""
            Text(
                text = prefix + (room.lastMessage?.content ?: "Chưa có tin nhắn"),
                style = MaterialTheme.typography.bodyMedium,
                color = if (isMine) MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f) else if (isUnread) MaterialTheme.colorScheme.onSurface else MaterialTheme.colorScheme.onSurfaceVariant,
                fontWeight = if (isUnread && !isMine) androidx.compose.ui.text.font.FontWeight.Bold else null,
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )
        },
        leadingContent = {
            Surface(
                shape = MaterialTheme.shapes.small,
                color = MaterialTheme.colorScheme.primaryContainer,
                modifier = Modifier.size(40.dp)
            ) {
                Box(contentAlignment = Alignment.Center) {
                    Text(
                        text = room.name.take(1).uppercase(),
                        style = MaterialTheme.typography.titleMedium,
                        color = MaterialTheme.colorScheme.onPrimaryContainer
                    )
                }
            }
        },
        trailingContent = {
            Column(horizontalAlignment = Alignment.End) {
                room.lastMessage?.createdAt?.let {
                    Text(
                        timeFormat.format(it),
                        style = MaterialTheme.typography.labelSmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
                if (unread > 0) {
                    Spacer(Modifier.height(4.dp))
                    Badge { Text(unread.toString()) }
                }
            }
        }
    )
}

package com.securechat.ui.screens.home

import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import androidx.lifecycle.compose.collectAsStateWithLifecycle
import com.securechat.domain.model.ChatRoom
import java.text.SimpleDateFormat
import java.util.Locale

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun HomeScreen(
    onOpenChat: (roomId: String, roomName: String) -> Unit,
    onSignedOut: () -> Unit,
    viewModel: HomeViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()
    val user = viewModel.currentUser

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("SecureChat") },
                actions = {
                    IconButton(onClick = { viewModel.signOut(onSignedOut) }) {
                        Icon(Icons.Default.Logout, contentDescription = "Đăng xuất")
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = MaterialTheme.colorScheme.primaryContainer
                )
            )
        },
        floatingActionButton = {
            FloatingActionButton(onClick = viewModel::showCreateDialog) {
                Icon(Icons.Default.Add, contentDescription = "Tạo phòng")
            }
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
        ) {
            user?.let {
                Surface(
                    color = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.4f),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Row(
                        modifier = Modifier.padding(horizontal = 16.dp, vertical = 12.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Icon(
                            Icons.Default.AccountCircle,
                            contentDescription = null,
                            modifier = Modifier.size(40.dp),
                            tint = MaterialTheme.colorScheme.primary
                        )
                        Spacer(Modifier.width(12.dp))
                        Column {
                            Text(it.displayName, style = MaterialTheme.typography.titleMedium)
                            Text(it.email,
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant)
                        }
                    }
                }
            }

            HorizontalDivider()

            if (uiState.isLoading && uiState.rooms.isEmpty()) {
                Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                    CircularProgressIndicator()
                }
            } else if (uiState.rooms.isEmpty()) {
                Box(Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Icon(
                            Icons.Default.ChatBubbleOutline,
                            contentDescription = null,
                            modifier = Modifier.size(64.dp),
                            tint = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.5f)
                        )
                        Spacer(Modifier.height(16.dp))
                        Text(
                            "Chưa có cuộc trò chuyện nào",
                            style = MaterialTheme.typography.bodyLarge,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                        Text(
                            "Nhấn + để tạo phòng mới",
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f)
                        )
                    }
                }
            } else {
                LazyColumn {
                    items(
                        items = uiState.rooms,
                        key   = { it.id }
                    ) { room ->
                        RoomItem(
                            room    = room,
                            currentUserId = user?.uid ?: "",
                            onClick = { onOpenChat(room.id, room.name) },
                            onLongClick = { viewModel.showDeleteRoomDialog(room.id) } // Needs to be added to view model
                        )
                        HorizontalDivider(modifier = Modifier.padding(start = 72.dp))
                    }
                }
            }
        }

        if (uiState.showCreateDialog) {
            AlertDialog(
                onDismissRequest = viewModel::dismissCreateDialog,
                title   = { Text("Tạo phòng chat mới") },
                text    = {
                    Column {
                        OutlinedTextField(
                            value = uiState.newRoomName,
                            onValueChange = viewModel::onNewRoomNameChange,
                            label = { Text("Tên phòng") },
                            singleLine = true,
                            modifier = Modifier.fillMaxWidth()
                        )
                        if (uiState.errorMessage != null) {
                            Text(
                                text = uiState.errorMessage!!,
                                color = MaterialTheme.colorScheme.error,
                                style = MaterialTheme.typography.bodySmall,
                                modifier = Modifier.padding(top = 8.dp)
                            )
                        }
                    }
                },
                confirmButton = {
                    TextButton(
                        onClick  = viewModel::createRoom,
                        enabled  = uiState.newRoomName.isNotBlank() && !uiState.isCreating
                    ) { 
                        if (uiState.isCreating) CircularProgressIndicator(Modifier.size(16.dp))
                        else Text("Tạo") 
                    }
                },
                dismissButton = {
                    TextButton(onClick = viewModel::dismissCreateDialog) { Text("Hủy") }
                }
            )
        }

        if (uiState.roomToDeleteId != null) {
            AlertDialog(
                onDismissRequest = viewModel::dismissDeleteRoomDialog,
                title = { Text("Xóa phòng chat") },
                text = { Text("Bạn có chắc chắn muốn xóa phòng chat này không? Tất cả tin nhắn sẽ bị xóa vĩnh viễn.") },
                confirmButton = {
                    TextButton(
                        onClick = { viewModel.deleteRoom(uiState.roomToDeleteId!!) }
                    ) {
                        Text("Xóa", color = MaterialTheme.colorScheme.error)
                    }
                },
                dismissButton = {
                    TextButton(onClick = viewModel::dismissDeleteRoomDialog) {
                        Text("Hủy")
                    }
                }
            )
        }
    }
}

@OptIn(androidx.compose.foundation.ExperimentalFoundationApi::class)
@Composable
private fun RoomItem(room: ChatRoom, currentUserId: String, onClick: () -> Unit, onLongClick: () -> Unit) {
    val timeFormat = remember { SimpleDateFormat("HH:mm", Locale.getDefault()) }
    val unread = room.unreadCount[currentUserId] ?: 0
    val isUnread = unread > 0
    val isMine = room.lastMessage?.senderId == currentUserId

    ListItem(
        modifier = Modifier.combinedClickable(
            onClick = onClick,
            onLongClick = onLongClick
        ),
        headlineContent = {
            Text(room.name, style = MaterialTheme.typography.titleMedium, fontWeight = if (isUnread) androidx.compose.ui.text.font.FontWeight.Bold else null)
        },
        supportingContent = {
            val prefix = if (isMine && room.lastMessage != null) "Bạn: " else ""
            Text(
                text = prefix + (room.lastMessage?.content ?: "Chưa có tin nhắn"),
                style = MaterialTheme.typography.bodyMedium,
                color = if (isMine) MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f) else if (isUnread) MaterialTheme.colorScheme.onSurface else MaterialTheme.colorScheme.onSurfaceVariant,
                fontWeight = if (isUnread && !isMine) androidx.compose.ui.text.font.FontWeight.Bold else null,
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )
        },
        leadingContent = {
            Surface(
                shape = MaterialTheme.shapes.small,
                color = MaterialTheme.colorScheme.primaryContainer,
                modifier = Modifier.size(40.dp)
            ) {
                Box(contentAlignment = Alignment.Center) {
                    Text(
                        text = room.name.take(1).uppercase(),
                        style = MaterialTheme.typography.titleMedium,
                        color = MaterialTheme.colorScheme.onPrimaryContainer
                    )
                }
            }
        },
        trailingContent = {
            Column(horizontalAlignment = Alignment.End) {
                room.lastMessage?.createdAt?.let {
                    Text(
                        timeFormat.format(it),
                        style = MaterialTheme.typography.labelSmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
                if (unread > 0) {
                    Spacer(Modifier.height(4.dp))
                    Badge { Text(unread.toString()) }
                }
            }
        }
    )
}
